  1	import React, { FC, useEffect, useMemo, useState } from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import { RHELAutomaticSubscriptionFormProps } from '@kubevirt-utils/hooks/useRHELAutomaticSubscription/utils/types';
  5	import { debounce } from '@kubevirt-utils/utils/debounce';
  6	import {
  7	  Button,
  8	  ButtonVariant,
  9	  Form,
 10	  FormGroup,
 11	  Grid,
 12	  GridItem,
 13	  Skeleton,
 14	  TextInput,
 15	} from '@patternfly/react-core';
 16	
 17	import { ACTIVATION_KEYS_URL } from '../../utils/constants';
 18	import ActivationKeyHelpIcon from '../ActivationKeyHelpIcon/ActivationKeyHelpIcon';
 19	import OrganizationIDHelpIcon from '../OrganizationIDHelpIcon/OrganizationIDHelpIcon';
 20	
 21	import './AutomaticSubscriptionForm.scss';
 22	
 23	const AutomaticSubscriptionForm: FC<RHELAutomaticSubscriptionFormProps> = ({
 24	  canEdit,
 25	  loaded,
 26	  subscriptionData,
 27	  updateSubscription,
 28	}) => {
 29	  const { t } = useKubevirtTranslation();
 30	
 31	  const [activationKey, setActivationKey] = useState<string>(null);
 32	  const [organizationID, setOrganizationID] = useState<string>(null);
 33	
 34	  useEffect(() => {
 35	    if (activationKey === null && organizationID === null && loaded) {
 36	      setActivationKey(subscriptionData?.activationKey);
 37	      setOrganizationID(subscriptionData?.organizationID);
 38	    }
 39	  }, [activationKey, loaded, organizationID, subscriptionData]);
 40	
 41	  const update = useMemo(
 42	    () =>
 43	      debounce((val) => {
 44	        updateSubscription(val);
 45	      }, 400),
 46	    [updateSubscription],
 47	  );
 48	
 49	  if (!loaded) return <Skeleton />;
 50	
 51	  return (
 52	    <>
 53	      <Form className="pf-v6-u-mt-sm" isHorizontal isWidthLimited>
 54	        <FormGroup
 55	          className="subscription-label"
 56	          label={t('Activation key')}
 57	          labelHelp={<ActivationKeyHelpIcon />}
 58	        >
 59	          <Grid hasGutter>
 60	            <GridItem span={7}>
 61	              <TextInput
 62	                onChange={(_event, val) => {
 63	                  setActivationKey(val);
 64	                  update({ activationKey: val });
 65	                }}
 66	                isDisabled={!canEdit}
 67	                value={activationKey}
 68	              />
 69	            </GridItem>
 70	            <GridItem span={5}>
 71	              <Button
 72	                component="a"
 73	                href={ACTIVATION_KEYS_URL}
 74	                target="_blank"
 75	                variant={ButtonVariant.link}
 76	              >
 77	                {t('Create activation key')}
 78	              </Button>
 79	            </GridItem>
 80	          </Grid>
 81	        </FormGroup>
 82	        <FormGroup
 83	          className="subscription-label"
 84	          label={t('Organization ID')}
 85	          labelHelp={<OrganizationIDHelpIcon />}
 86	        >
 87	          <Grid hasGutter>
 88	            <GridItem span={7}>
 89	              <TextInput
 90	                onChange={(_event, val) => {
 91	                  setOrganizationID(val);
 92	                  update({ organizationID: val });
 93	                }}
 94	                isDisabled={!canEdit}
 95	                value={organizationID}
 96	              />
 97	            </GridItem>
 98	          </Grid>
 99	        </FormGroup>
100	      </Form>
101	    </>
102	  );
103	};
104	
105	export default AutomaticSubscriptionForm;

